const response = $input.item.json.choices[0].message.content;
let content;
try {
  content = JSON.parse(response);
} catch {
  const clean = response.replace(/```json\n?/g,'').replace(/```/g,'').trim();
  content = JSON.parse(clean);
}

return {
  tiktok: content.tiktok,
  instagram: content.instagram,
  youtube: content.youtube
};

const meta = {
  video_id: $node['Extract Channel'].json.videoId,
  channel: $node['Extract Channel'].json.channel,
  filename: $node['Extract Channel'].json.filename,
  transcription: $node['Whisper Transcribe'].json.text,
  content: {
    tiktok: $json.tiktok,
    instagram: $json.instagram,
    youtube: $json.youtube
  },
  created: new Date().toISOString()
};

const fs = require('fs');
const dir = '/workspace/.state/videos';
if (!fs.existsSync(dir)) fs.mkdirSync(dir, {recursive: true});
fs.writeFileSync(`${dir}/${meta.video_id}.json`, JSON.stringify(meta, null, 2));

return {json: meta};
